// CheckThinkWithOpts(IncludeAll=false) 等同舊 CheckThink：略過無 @ai:generated 的 func
func TestCheckThinkWithOpts_DefaultSkipsNonGenerated(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "x.go")
	src := `package example

// Human 是人類寫的（沒有 @ai:generated）。
func Human() {
	println("human")
}

// AIGen
// @ai:generated by=x date=2026-06-19
func AIGen() {
	println("ai")
}
`
	if err := os.WriteFile(path, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	report, err := CheckThinkWithOpts(path, CheckThinkOpts{})
	if err != nil {
		t.Fatal(err)
	}
	if report.Scanned != 1 {
		t.Errorf("scanned = %d, want 1 (only @ai:generated)", report.Scanned)
	}
	if len(report.Missing) != 1 || report.Missing[0].Name != "AIGen" {
		t.Errorf("missing = %+v, want [AIGen]", report.Missing)
	}
}

// CheckThinkWithOpts(IncludeAll=true) 把所有 func 都納入
func TestCheckThinkWithOpts_IncludeAllScansEveryFunc(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "x.go")
	src := `package example

// Human 是人類寫的（沒有 @ai:generated）。
func Human() {
	println("human")
}

// AIGen
// @ai:generated by=x date=2026-06-19
func AIGen() {
	println("ai")
}

// Already 已有 think 的，不該再進 missing
// @ai:generated by=x date=2026-06-19
func Already() {
	//@ai:think intent=已有 model=x
	println("already")
}
`
	if err := os.WriteFile(path, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	report, err := CheckThinkWithOpts(path, CheckThinkOpts{IncludeAll: true})
	if err != nil {
		t.Fatal(err)
	}
	if report.Scanned != 3 {
		t.Errorf("scanned = %d, want 3", report.Scanned)
	}
	// Missing = Human + AIGen（Already 已有 think）
	if len(report.Missing) != 2 {
		t.Fatalf("missing = %d, want 2", len(report.Missing))
	}
	names := map[string]bool{}
	for _, m := range report.Missing {
		names[m.Name] = true
	}
	if !names["Human"] || !names["AIGen"] {
		t.Errorf("missing names = %+v, want both Human and AIGen", names)
	}
	if names["Already"] {
		t.Error("Already has @ai:think, should NOT be in missing")
	}
}

// stub suggester：可以從 req.Retroactive 觀察到旗標傳遞
type retroStub struct {
	gotRetroactive bool
	intent         string
}

func (s *retroStub) ModelName() string { return "stub-model" }
func (s *retroStub) SuggestThink(_ context.Context, req ThinkSuggestRequest) (ThinkSuggestion, error) {
	s.gotRetroactive = req.Retroactive
	return ThinkSuggestion{Intent: s.intent}, nil
}

// FixThinkFileWithOpts retroactive=true 時：
//   - prompt 切換為 retroactive 模式（透過觀察 req.Retroactive）
//   - 插入的 //@ai:think 帶 retroactive=true 標籤
func TestFixThinkFileWithOpts_RetroactiveAddsTag(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "x.go")
	src := `package example

// Plain 沒有 @ai:generated。
func Plain() {
	println("hi")
}
`
	if err := os.WriteFile(path, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	report, err := CheckThinkWithOpts(path, CheckThinkOpts{IncludeAll: true})
	if err != nil {
		t.Fatal(err)
	}
	if len(report.Missing) != 1 {
		t.Fatalf("missing = %d, want 1", len(report.Missing))
	}

	s := &retroStub{intent: "事後反推：印 hi"}
	fixed, err := FixThinkFileWithOpts(context.Background(), path, report, s, FixThinkOpts{Retroactive: true})
	if err != nil {
		t.Fatal(err)
	}
	if fixed != 1 {
		t.Errorf("fixed = %d, want 1", fixed)
	}
	if !s.gotRetroactive {
		t.Error("Retroactive flag was not propagated to suggester")
	}

	data, _ := os.ReadFile(path)
	out := string(data)
	if !strings.Contains(out, "retroactive=true") {
		t.Errorf("expected `retroactive=true` tag in output:\n%s", out)
	}
	if !strings.Contains(out, "intent=事後反推：印 hi") {
		t.Errorf("expected suggested intent in output:\n%s", out)
	}
	if !strings.Contains(out, "model=stub-model") {
		t.Errorf("expected model tag in output:\n%s", out)
	}
}

// 不帶 opts → 等同舊行為（無 retroactive 標籤）
func TestFixThinkFile_BackwardCompatNoRetroactiveTag(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "x.go")
	src := `package example

// AIGen
// @ai:generated by=x date=2026-06-19
func AIGen() {
	println("hi")
}
`
	if err := os.WriteFile(path, []byte(src), 0644); err != nil {
		t.Fatal(err)
	}

	report, err := CheckThink(path)
	if err != nil {
		t.Fatal(err)
	}

	s := &retroStub{intent: "建立資源"}
	if _, err := FixThinkFile(context.Background(), path, report, s); err != nil {
		t.Fatal(err)
	}
	if s.gotRetroactive {
		t.Error("Default FixThinkFile should NOT pass Retroactive=true")
	}

	data, _ := os.ReadFile(path)
	out := string(data)
	if strings.Contains(out, "retroactive=true") {
		t.Errorf("backward-compat path should NOT add retroactive tag:\n%s", out)
	}
}

// buildThinkPrompt 切換 prompt 字串
func TestBuildThinkPrompt_RetroactiveUsesDifferentSystem(t *testing.T) {
	normal := buildThinkPrompt(ThinkSuggestRequest{FuncName: "Foo", Kind: "func"})
	retro := buildThinkPrompt(ThinkSuggestRequest{FuncName: "Foo", Kind: "func", Retroactive: true})

	if !strings.Contains(normal, "設計意圖") {
		t.Error("normal prompt should mention 設計意圖")
	}
	if strings.Contains(normal, "事後分析") {
		t.Error("normal prompt should NOT mention 事後分析")
	}
	if !strings.Contains(retro, "事後") {
		t.Error("retroactive prompt should mention 事後")
	}
	if !strings.Contains(retro, "你並不是原作者") {
		t.Error("retroactive prompt should clarify you are not the author")
	}
}

