// heuristicIntentFor 在 retroactive 模式下要正確改寫，誠實標示 heuristic 出處
func TestHeuristicIntentFor_Retroactive(t *testing.T) {
	tests := []struct {
		name        string
		retroactive bool
		want        string
	}{
		{"CreateUser", false, "建立資源"},
		{"CreateUser", true, "推測：建立資源"},
		{"runGUI", false, "啟動服務"},
		{"runGUI", true, "推測：啟動服務"},
		// 不在 heuristic prefix 表內 → retroactive 模式給更明確的訊息
		{"main", false, "TODO: 說明此函式的意圖"},
		{"main", true, "TODO: 反推此函式的實際職責（heuristic 無法依名稱判定）"},
		{"usage", true, "TODO: 反推此函式的實際職責（heuristic 無法依名稱判定）"},
	}
	for _, tt := range tests {
		got := heuristicIntentFor(tt.name, tt.retroactive)
		if got != tt.want {
			t.Errorf("heuristicIntentFor(%q, %v) = %q, want %q", tt.name, tt.retroactive, got, tt.want)
		}
	}
}

